import Link from 'next/link'
import { verbs } from '@/data/verbs'
export default function Home(){ const today = verbs[0]; return <div className="space-y-8"><header><h1 className="text-2xl font-semibold tracking-tight">Verb Master</h1><p className="mt-1 text-sm text-gray-500">Know the verb. Use the verb.</p></header><section className="rounded-3xl bg-white p-7 shadow-sm"><p className="text-sm text-gray-500">Today's Verb</p><h2 className="mt-3 text-5xl font-semibold tracking-tight">{today.word}</h2><p className="mt-4 text-gray-600">{today.core}</p><Link href={`/verbs/${today.id}`} className="mt-6 block rounded-full bg-[#1f4e5f] py-3 text-center text-white">学習する</Link></section><section className="space-y-3"><Link className="block rounded-2xl bg-white p-5 shadow-sm" href="/verbs">動詞一覧</Link><Link className="block rounded-2xl bg-white p-5 shadow-sm" href="/tests">テスト</Link><Link className="block rounded-2xl bg-white p-5 shadow-sm" href="/profile">学習記録・ランキング</Link></section></div> }
